What does this program print?

```cpp
#include <iostream>
int main() {
    int x = 5;
    std::cout << ((x > 0) && (x < 10)) << "\n";
    std::cout << ((x < 0) || (x > 3))  << "\n";
    std::cout << (!(x == 5))            << "\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
int main() {
    int counter = 0;
    bool result = (counter != 0) && (++counter > 0);
    std::cout << counter << "\n";
    std::cout << result  << "\n";
    return 0;
}
```

The programmer wants to print `safe` when `divisor` is not zero and the quotient is positive. What is wrong?

```cpp
#include <iostream>
int main() {
    int divisor = 0;
    int numerator = 10;
    if ((numerator / divisor > 0) && (divisor != 0)) {
        std::cout << "safe\n";
    } else {
        std::cout << "unsafe\n";
    }
    return 0;
}
```
